#include <stdio.h>
#include <omp.h>

void findK(	long height,
			knode *knodesD,
			long knodes_elem,
			record *recordsD,

			long *currKnodeD,
			long *offsetD,
			int *keysD, 
			record *ansD,
            int order,  // Passed order needed for loop bounds
            int count) // Passed count needed for loop bounds
{

    // Parallelize over bid (equivalent to blockIdx.x)
    #pragma omp parallel for
    for (int bid = 0; bid < count; ++bid) {
        // Each thread corresponds to thid (threadIdx.x)
        // We simulate threads by a loop over thid
        for (int i = 0; i < height; i++) {
            // We need to simulate the __syncthreads by ensuring all thid work is done before updating currKnodeD[bid]
            // So first compute all thid work and then update currKnodeD[bid]

            // Use temporary variable for offset update
            long local_offset = offsetD[bid];
            int key = keysD[bid];
            long curr_knode = currKnodeD[bid];

            // Because thid is from 0 to order-1, and knodesD[curr_knode].keys has order+1 keys
            // So to avoid out-of-bounds, thid runs from 0 to order-1
            // We'll iterate thid from 0 to order-1
            for (int thid = 0; thid < order; thid++) {
                if ((knodesD[curr_knode].keys[thid] <= key) && (knodesD[curr_knode].keys[thid+1] > key)) {
                    if (knodesD[offsetD[bid]].indices[thid] < knodes_elem) {
                        local_offset = knodesD[offsetD[bid]].indices[thid];
                    }
                }
            }
            offsetD[bid] = local_offset;

            // Now update currKnodeD[bid] by thid == 0 thread in CUDA
            currKnodeD[bid] = offsetD[bid];
        }

        // After finishing the height iterations, do final check for ansD assignment
        long curr_knode = currKnodeD[bid];
        int key = keysD[bid];

        // Again simulate the threads for thid
        for (int thid = 0; thid < order; thid++) {
            if (knodesD[curr_knode].keys[thid] == key) {
                ansD[bid].value = recordsD[knodesD[curr_knode].indices[thid]].value;
            }
        }
    }
}

