#include <stdio.h>
#include <omp.h>

void findRangeK(	long height,

				knode *knodesD,
				long knodes_elem,

				long *currKnodeD,
				long *offsetD,
				long *lastKnodeD,
				long *offset_2D,
				int *startD,
				int *endD,
				int *RecstartD, 
				int *ReclenD,
                int order, // passed order for loop bounds
                int count) // passed count for loop bounds
{

    // Parallel over bid simulating blockIdx.x
    #pragma omp parallel for
    for (int bid = 0; bid < count; ++bid) {
        for (int i = 0; i < height; i++) {
            long curr_knode = currKnodeD[bid];
            long last_knode = lastKnodeD[bid];

            long local_offset = offsetD[bid];
            long local_offset_2 = offset_2D[bid];
            int start = startD[bid];
            int end = endD[bid];

            for (int thid = 0; thid < order; thid++) {
                if ((knodesD[curr_knode].keys[thid] <= start) && (knodesD[curr_knode].keys[thid+1] > start)) {
                    if (knodesD[currKnodeD[bid]].indices[thid] < knodes_elem) {
                        local_offset = knodesD[curr_knode].indices[thid];
                    }
                }
                if ((knodesD[last_knode].keys[thid] <= end) && (knodesD[last_knode].keys[thid+1] > end)) {
                    if (knodesD[last_knode].indices[thid] < knodes_elem) {
                        local_offset_2 = knodesD[last_knode].indices[thid];
                    }
                }
            }
            offsetD[bid] = local_offset;
            offset_2D[bid] = local_offset_2;

            // Update currKnodeD and lastKnodeD by simulated thid == 0 thread in CUDA
            currKnodeD[bid] = offsetD[bid];
            lastKnodeD[bid] = offset_2D[bid];
        }

        long curr_knode = currKnodeD[bid];
        long last_knode = lastKnodeD[bid];
        int start = startD[bid];
        int end = endD[bid];

        // Set RecstartD[bid]
        for (int thid = 0; thid < order; thid++) {
            if (knodesD[curr_knode].keys[thid] == start) {
                RecstartD[bid] = knodesD[curr_knode].indices[thid];
            }
        }

        // Set ReclenD[bid]
        for (int thid = 0; thid < order; thid++) {
            if (knodesD[last_knode].keys[thid] == end) {
                ReclenD[bid] = knodesD[last_knode].indices[thid] - RecstartD[bid] + 1;
            }
        }
    }
}
